Class MessageDisplay Extends %RegisteredObject
{
    /// Format message for HTML display
    ClassMethod DisplayMessage(message As %String) As %String
    {
        // BUGGY: No HTML escaping - allows XSS attacks
        Set html = "<div class='message'>" _ message _ "</div>"
        Quit html
    }
}

