Class TestMessageDisplay Extends %RegisteredObject
{
    ClassMethod TestDisplayMessage()
    {
        // Normal message should work
        Set result = ##class(MessageDisplay).DisplayMessage("Hello World")
        If (result '[ "Hello World") {
            Throw ##class(%Exception.General).%New("Normal message not displayed")
        }

        // HTML special chars should be escaped
        Set result = ##class(MessageDisplay).DisplayMessage("<script>alert('xss')</script>")
        If (result [ "<script>") {
            Throw ##class(%Exception.General).%New("Script tag not escaped - XSS vulnerability!")
        }

        // Check & is escaped
        Set result = ##class(MessageDisplay).DisplayMessage("A & B")
        If (result [ " & ") {
            If (result '[ "&amp;") {
                Throw ##class(%Exception.General).%New("Ampersand not escaped")
            }
        }
    }
}
